import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"血之冲突系列","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/血之冲突系列.md","filePath":"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/血之冲突系列.md"}'),s={name:"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/血之冲突系列.md"};function o(d,b,D,_,l,i){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"血之冲突系列",tabindex:"-1"},[t("血之冲突系列 "),r("a",{class:"header-anchor",href:"#血之冲突系列","aria-label":'Permalink to "血之冲突系列"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风020")])])],-1),n('<h1 id="血之冲突系列-1" tabindex="-1">血之冲突系列 <a class="header-anchor" href="#血之冲突系列-1" aria-label="Permalink to &quot;血之冲突系列&quot;">​</a></h1><p>血之冲突系列<br> 附录1：该系列下属所有物品均为【消耗品-药物】，可使用次数将单独标记在类型后，大多数药物都会具有一项副作用。<br> 附录2：具有持续时间词条的药物，持续时间只影响药物好处的持续时间，与副作用无关。<br> 附录3：主神空间可以免费清除戒断反应。</p><p>武士道<br> 类型：消耗品（1）<br> 价格：250<br> 持续：3+传奇耐力*1轮<br> 描述：昂贵，而且时常缺货的绿色营养剂，只要一支就能让注意力在短时间内集中，使用的方法是静脉注射。<br> 效果：<br> 【集中】持续时间内，被注射者在攻击检定上获得3DP增强加值。<br> 【副作用】使用时会对自身造成1点不可减免毒素严重伤害，若因其他效果无视了这一副作用，则集中提供的加值减少1点。</p><p>药物疲劳<br> 一档：加值降低1点。<br> 二档：加值降低2点。<br> 三档：药效完全失效。</p><p>猩红牛<br> 类型：消耗品（3）<br> 价格：1000<br> 持续：一轮<br> 描述：需要医生许可才能购买的，特殊的红色营养剂，只需要1/3支就能达到更好的效果，使用的方法是静脉注射。<br> 效果：<br> 【狂热】持续时间内，被注射者在攻击检定上获得7DP增强加值，以及在攻击上获得2个附加成功。<br> 【副作用】使用时会对自身造成2点不可减免毒素严重伤害，若因其他效果无视了这一副作用，则狂热提供的加值减少2点。</p><p>药物疲劳<br> 一档：加值降低1点，附加减少1点。<br> 二档：加值降低3点，附加减少1点。<br> 三档：加值降低4点，失去附加成功。<br> 四档：药效完全失效。</p><p>怪物<br> 类型：消耗品（1）<br> 价格：D+500<br> 持续：3+传奇耐力*1轮<br> 描述：光是持有就会受到10年以下的监禁或是500万元以下处罚，蓝色的非法营养剂，使用的方法是静脉注射。<br> 效果：<br> 【暴走】持续时间内，被注射者的力量检定获得12DP增强加值，在相关检定上获得4个附加成功，体积增加3点，这是虚拟体积，不会提供生命值的提升。<br> 【副作用】使用时会对自身造成2点不可减免毒素严重伤害，若因其他效果无视了这一副作用，则暴走提供的加值减少2点。</p><p>药物疲劳<br> 一档：加值降低3点，附加减少1点。<br> 二档：加值降低6点，附加减少2点。<br> 三档：加值降低9点，附加减少3点，不获得体积加值。<br> 四档：药效完全失效。</p><p>E药片<br> 类型：消耗品（3）<br> 价格：1000<br> 持续：立即<br> 描述：使用炼金术和现代医术打造的解药物，使用方式是吞服。<br> 【解毒剂】：服用后立刻解除服用者身上承受的，不超过C级毒素来源的效果影响。<br> 【副作用】：无</p><p>药物疲劳<br> 一档：解除等级降低1级（C-D）<br> 二档：解除等级降低2级（C-D-无支线）<br> 三档：药效完全失效</p><p>C药片<br> 类型：消耗品（3）<br> 价格：1000<br> 持续：一轮<br> 描述：使用炼金术和现代医术打造的感知增强药物，使用方式是吞服。<br> 效果：<br> 【感官增强】：持续时间内，服用者获得D级自然本质的侦查能力，同时在感知检定上获得3DP增强加值。<br> 此外，任选自身一项感知能力，若选择嗅觉，则可以使用嗅觉模糊定位。若选择听觉，则可以使用听觉模糊定位。若选择视觉，则可以降低2DP感知上的增强加值，将该药物提供的侦查等级提升至C级，必须在购买时选择是提升嗅/听/视觉哪一种。<br> 【副作用】：无</p><p>药物疲劳<br> 一档：药效完全失效</p><p>V药片<br> 类型：消耗品（1）<br> 价格：250<br> 持续：永久<br> 描述：使用炼金术和现代医术打造的智力增强药物，使用方式是吞服，但吃多了会变成白痴。<br> 效果：<br> 【多智】服用者在智力检定上永久性获得1DP增强加值，每服用2次，额外增加1DP同类型加值。<br> 【封闭】服用者在感知检定上永久性获得1DP内在减值，若该减值超过4点，则服用者永久性变成一个白痴，如同死亡一样计算。</p><p>药物疲劳：无</p><p>香水<br> 类型：消耗品（1）<br> 价格：1000<br> 持续：一小时<br> 描述：喷洒在身上的香水，可以在一定时间内增加使用者的魅力。<br> 效果：<br> 【洛费蒙】持续时间内，使用者的风度检定获得6DP增强加值。<br> 【副作用】无</p><p>药物疲劳<br> 一档：药效完全失效</p><p>香烟<br> 类型：消耗品（1）<br> 价格：500<br> 持续：3+传奇耐力*1轮<br> 描述：「布拉德德斯门索尔」牌香烟，焦油15mm，能缓解绝大多数不适感，跟抽镇定剂没什么区别。<br> 效果：<br> 【麻醉品】：持续期间，使用者每轮恢复1点任意不良点数。<br> 【副作用】：使用时，承受1点不可避免的毒素严重伤害。</p><p>药物疲劳<br> 一档：药效完全失效</p><p>蓝色-蓝色饮料<br> 类型：消耗品（3）<br> 价格：500<br> 持续：一影片<br> 描述：含有大量咖啡-咖啡因的功能性饮料，其中蕴含着人体必备的一切消耗，只要摄入1/3杯就能长期工作，无需休息也无需进食。<br> 效果：<br> 【振奋】使用者将在持续时间内无需睡眠与饮食，不会因为常规工作而猝死。<br> 【副作用】无</p><p>药物疲劳<br> 一档：药效完全失效</p><p>小碗杯面<br> 类型：消耗品（1）<br> 价格：500<br> 持续：3+传奇耐力*1轮<br> 描述：垃圾食品的代表，好像有酱油味，味增味和咖啡味，因为投放了大量防疫用纳米机器，吃完会感觉身体变硬了。<br> 效果：<br> 【纳米硬化】食用者获得4点天生防御，以及基于天生防御的【防弹】。若已有【防弹】能力，则改为获得5点天生防御，以及1点抵破甲能力。<br> 【副作用】食用时承受1点不可避免的麻痹不良点数。</p><p>药物疲劳<br> 一档：天生防御降低1点<br> 二档：天生防御降低2点，失去防弹能力，失去抵破甲<br> 三档：天生防御降低3点，失去防弹能力，失去抵破甲<br> 四挡：药效完全失效</p><p>牛背面便当<br> 类型：消耗品（3）<br> 价格：D+500<br> 持续：3+传奇耐力*1轮<br> 描述：咸甜味的佐料勾起食欲，因为投放了大量防疫用纳米机器，吃完会感觉身体坚不可摧。<br> 效果：<br> 【纳米-纳面硬化】食用者的天生防御提升7点，同时获得基于天生防御的【全伤害吸收2】，以及在强韧豁免上获得2DP器械加值。<br> 【副作用】食用时承受2点不可避免的麻痹不良点数。</p><p>药物疲劳<br> 一档：天生防御降低2点，失去强韧豁免加值<br> 二档：天生防御降低3点，全伤害吸收减少1点，失去强韧豁免加值<br> 三档：天生防御降低3点，失去全伤害吸收，失去强韧豁免加值<br> 四挡：药效完全失效</p><p>清水<br> 类型：消耗品（9）<br> 价格：1000<br> 持续：一日<br> 描述：相当好喝的清水，口感甜润，广受市民喜爱。<br> 效果：<br> 【完美】使用者在全检定上获得1DP增强加值。<br> 【戒断反应】使用者若在一日内没有使用清水，则在全检定上获得1DP士气减值，减值不会叠加。</p><p>药物疲劳：<br> 一档：药效完全失效</p><p>矿泉水<br> 类型：消耗品（9）<br> 价格：D+500<br> 持续：一日<br> 描述：异常好喝的矿泉水，饮用的时候需要有人在旁边提醒，否则只要打开就会忍不住喝光。<br> 效果：<br> 【完美】使用者在全检定上获得2DP增强加值，机运检定结果+1。<br> 【戒断反应】使用者若在一日内没有使用矿泉水，则在全检定上获得2DP士气减值，机运检定结果-1，减值不会叠加。</p><p>药物疲劳：<br> 一档：全检定加值降低1点。<br> 二档：全检定加值降低1点，失去幸运结果+1。<br> 三档：药效完全失效</p><p>深海-海洋水<br> 类型：消耗品（1）<br> 价格：C+1000<br> 持续：一小时<br> 描述：矿物似乎是从海底提取的，具有强力的成瘾性，非万不得已的场合请不要使用。<br> 效果：<br> 【完美】使用者在全检定上获得8DP增强加值，机运检定结果+2。<br> 【戒断反应】使用者若在一日内没有使用深海-海洋水，则在全检定上获得8DP士气减值，机运检定结果-12，减值不会叠加。</p><p>药物疲劳：<br> 一档：全检定加值降低2点。<br> 二档：全检定加值降低4点，机运检定结果下降1点。<br> 三档：全检定加值降低6点，失去机运结果+2。<br> 四档：药物完全失效</p><p>一次性钢管<br> 类型：消耗品（1）<br> 价格：D+500<br> 持续：一轮<br> 描述：原本的名字叫做【一次性电击枪】，一次性钢管其实是错误的翻译，包括外观在内有贴图错误的问题，分类也被错误的丢进了药物消耗品当中。<br> 效果：<br> 【电击】使用者本轮内进行攻击时，附带7点不可豁免的麻痹不良点数，以及1点攻击附加成功。<br> 【副作用】无</p><p>药物疲劳？<br> 一档：麻痹不良点数降低2点。<br> 二档：麻痹不良点数降低4点。<br> 三档：麻痹不良点数降低4点，失去附加成功。<br> 四挡：药效完全失效</p><p>处方药<br> 类型：消耗品（1）<br> 价格：250<br> 持续：3+传奇耐力*1轮<br> 描述：使用多种接近违法的药物组合而成的紧急药物，味道很苦，使用方式是鼻腔吸入。<br> 效果：<br> 【疗伤】持续时间内，使用者每轮恢复1点生命值。<br> 【副作用】承受1点可豁免的反胃不良点数，可叠加。</p><p>药物疲劳<br> 一档：持续时间下降为1+传奇耐力*1轮<br> 二档：持续时间下降为传奇耐力*1轮<br> 三档：药效完全失效</p><p>高级处方药<br> 价格：D+500<br> 类型：消耗品（1）<br> 持续：3+传奇耐力*1轮<br> 描述：使用多种接近合法的药物组合而成的紧急药物，味道非常的苦，使用方式是鼻腔吸入。<br> 效果：<br> 【高级疗伤】持续时间内，使用者获得6点快速医疗，以及3DP的三豁免增强加值。<br> 【副作用】承受2点不可避免的反胃不良点数，可叠加。</p><p>药物疲劳<br> 一档：快速医疗下降1点，三豁免加值减少2点。<br> 二档：快速医疗下降3点，三豁免加值减少2点。<br> 三档：快速医疗下降4点，失去三豁免加值。<br> 四档：药效完全失效。</p><p>超级处方药<br> 类型：消耗品（1）<br> 价格：B+2000<br> 描述：完全不考虑合法的处方药，连死人也会一时被苦的从地上坐起来，只要处于粉尘范围内就会生效。<br> 效果：<br> 这个药物必须是自愿目标才能服用，且服用后立刻承受等同自身决心/耐力（取高）的反胃不良点数，正常豁免，不可叠加，不会因此进入严重后果。<br> 明显的，死人并不具有拒绝的权利，会无条件视为同意服用，但因迷情或控制类效果服用的单位则不会获得该药物提供的好处和坏处。<br> 正常服用（或者被灌进嘴里）的场合，若服用者已经死亡，将立刻原地复活，这是一个B级来源药物的复活效果，处于战斗场景下则复活的单位会在战斗场景结束后倒下，非战斗场景时，这一复活效果将持续一个小时。</p><p>药物疲劳：无</p><p>升级（A+4000）：神之处方药<br> 分类：消耗品（特殊）<br> 描述：超越了传说中的超级处方药的超级处方药之神的处方药，因为名字实在太长被叫做神之处方药，药效持续时间略微下降但拥有了量产的能力，可以一次性投掷大量粉末，让接触到的友方全体被苦到苏生。<br> 效果：<br> 购买神之处方药后，每日可以获得【1】份神之处方药，神之处方药同时存在的数量不会超过【1】份。<br> 你可以消费一个自由动作，通过投掷的方式，让以自身为中心，范围等同于力量*20米的所有友方单位立刻复活，这是一个A级复活效果，然而每影片的时间内，每人只能因此享受一次神之处方药带来的复活效果，复活持续时间为一场景，场景结束后会再次倒下。<br> 你也可以提前为自己预留一份神之处方药，使自身也可以在死后立刻复活，复活是一个A级药物来源的效果。</p><p>这个药物必须是自愿目标才能服用，且服用后立刻承受等同自身决心/耐力（取高）两倍的反胃不良点数，正常豁免，不可叠加，不会因此进入严重后果。<br> 明显的，死人并不具有拒绝的权利，会无条件视为同意服用，但因迷情或控制类效果服用的单位则不会获得该药物提供的好处和坏处。</p><p>药物疲劳：无</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',43)])])}const h=p(s,[["render",o]]);export{c as __pageData,h as default};
